function isNum(v) {
    return typeof v === "number" && isFinite(v);
}

function clone(obj) {
    return JSON.parse(JSON.stringify(obj || {}));
}

function installed(hw, name) {
    return hw && hw[name] === true;
}

function addFault(faults, name, msgText) {
    faults[name] = msgText;
}

function finalizeFaults(obj) {
    let out = clone(obj);
    let faults = {};
    let missing = [];
    let hw = out.hw || {};

    function requireNumber(field, opts) {
        opts = opts || {};
        let installKey = opts.installKey || null;
        if (installKey && !installed(hw, installKey)) {
            addFault(faults, field, "NOT INSTALLED");
            out[field] = null;
            return;
        }
        if (!(field in out) || out[field] === null || out[field] === "") {
            addFault(faults, field, "MISSING");
            missing.push(field);
            return;
        }
        if (!isNum(out[field])) {
            addFault(faults, field, "INVALID");
            return;
        }
        if (isNum(opts.min) && out[field] < opts.min) addFault(faults, field, "INVALID");
        if (isNum(opts.max) && out[field] > opts.max) addFault(faults, field, "INVALID");
    }

    function requireBool(field, opts) {
        opts = opts || {};
        let installKey = opts.installKey || null;
        if (installKey && !installed(hw, installKey)) {
            addFault(faults, field, "NOT INSTALLED");
            out[field] = null;
            return;
        }
        if (!(field in out) || out[field] === null || out[field] === "") {
            addFault(faults, field, "MISSING");
            missing.push(field);
            return;
        }
        if (!(out[field] === true || out[field] === false)) {
            addFault(faults, field, "INVALID");
        }
    }

    requireNumber("temp_f", {min: -40, max: 150});
    requireNumber("rh_pct", {min: 0, max: 100});
    requireNumber("lux", {min: 0, max: 150000});
    requireNumber("louvre_pos_pct", {min: 0, max: 100});
    requireNumber("fan_pwm", {min: 0, max: 255});

    if (!("louvre_state" in out) || out.louvre_state === null || out.louvre_state === "") {
        addFault(faults, "louvre_state", "MISSING");
        missing.push("louvre_state");
    }

    requireNumber("soil1_pct", {installKey: "soil1", min: 0, max: 100});
    requireNumber("soil2_pct", {installKey: "soil2", min: 0, max: 100});
    requireNumber("soil3_pct", {installKey: "soil3", min: 0, max: 100});
    requireNumber("soil4_pct", {installKey: "soil4", min: 0, max: 100});

    requireNumber("tank_temp_f", {installKey: "tank_temp", min: -40, max: 180});
    requireBool("pump_on", {installKey: "pump"});
    requireBool("heater_on", {installKey: "heater"});
    requireBool("pv_present", {installKey: "pv"});

    if (isNum(out.fault) && out.fault !== 0) {
        addFault(faults, "controller_fault", "ARDUINO fault=" + out.fault);
    }

    if (out.fallback_used === true) {
        addFault(faults, "data_quality", "LAST GOOD SAMPLE");
    }

    if (commFault === 1) {
        addFault(faults, "comms", "NO COMMS TO ARDUINO");
    }

    out.faults = faults;
    out.fault_count = Object.keys(faults).length;
    out.system_fault = out.fault_count > 0 ? 1 : 0;
    out.missing_fields = missing.join(",");
    out.source = "sensor";

    // Compute canonical soil_avg_pct (hw-aware, fault-aware, single source of truth)
    let soilVals = [];
    ["soil1","soil2","soil3","soil4"].forEach(function(name) {
        let field = name + "_pct";
        if (!installed(hw, name)) return;
        if (faults[field]) return;
        if (!(field in out) || out[field] === null || out[field] === "") return;
        if (!isNum(out[field])) return;
        if (out[field] < 0 || out[field] > 100) return;
        soilVals.push(out[field]);
    });
    out.soil_avg_pct = soilVals.length > 0
        ? soilVals.reduce(function(a,b){return a+b;},0) / soilVals.length
        : null;

    return out;
}

