var sqlVals = cols.map(function(c) { return sqlVal(c[1], c[2]); });
var csvVals = cols.map(function(c) { return csvVal(c[1], c[2]); });

var sqlMsg = {
  topic: 'INSERT INTO greenhouse_samples (' + names.join(',') + ') VALUES (' + sqlVals.join(',') + ');',
  payload: []
};
var csvMsg = {
  payload: csvVals.join(',') + '\n'
};

return [sqlMsg, csvMsg];
